import { db } from "@/lib/db";
import { decryptSecret } from "@/lib/crypto";

export class LocalFalconClient {
  private organizationId: string;
  private apiKey: string | null = null;

  constructor(organizationId: string) {
    this.organizationId = organizationId;
  }

  async init() {
    const cred = await db.orgCredential.findFirst({
      where: { organizationId: this.organizationId, service: "LOCAL_FALCON", isValid: true },
    });

    if (cred) {
      this.apiKey = await decryptSecret(cred.encryptedKey, cred.keyId || undefined);
    }
  }

  get isConnected() {
    return this.apiKey !== null;
  }

  async getGridScan(locationId: string, keyword: string) {
    if (!this.isConnected) throw new Error("Local Falcon Not Connected");

    // Start a scan
    const response = await fetch("https://api.localfalcon.com/api/v1/reports/run", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${this.apiKey}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        location_id: locationId,
        keyword: keyword,
        grid_size: "3x3",
        grid_radius: "1.0mi",
      }),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`Local Falcon API Error: ${response.status} ${errorText}`);
    }

    const data = await response.json();
    return { locationId, keyword, reportId: data.report_id || null, data };
  }
}
